class Solution:
    def bubbleSort(self, arr):
        n = len(arr)
        swapped = True
        while n >= 1 and swapped:
            swapped = False
            for i in range(n - 1):
                if arr[i] > arr[i + 1]:
                    arr[i], arr[i + 1] = arr[i + 1], arr[i]
                    swapped = True
        return arr == sorted(arr)

if __name__ == '__main__':
    arr = [5, 3, 8, 2]
    solution = Solution()
    print(solution.bubbleSort(arr))

